import React from "react";
import { Link } from "react-router-dom";
import "../styles/Navbar.css";

export default function Navbar() {
  return (
    <div className="navbar">
      <h2>SHOP.CO</h2>

      <div>
        <Link to="/">Home</Link>
        <Link to="/products">Shop</Link>
        <Link to="/cart">Cart 🛒</Link>
      </div>
    </div>
  );
}
